import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../api/axios';
import { useAuth } from '../context/AuthContext';

const STATUS_COLOR = {
  Draft: { bg: '#f3f4f6', color: '#6b7280' },
  Pending: { bg: '#fef3c7', color: '#92400e' },
  Approved: { bg: '#d1fae5', color: '#065f46' },
  Rejected: { bg: '#fee2e2', color: '#991b1b' },
  Waiting: { bg: '#e0e7ff', color: '#3730a3' },
};

export default function EmployeeDashboard() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [expenses, setExpenses] = useState([]);

  useEffect(() => {
    if (!user) return;
    api.get('/expenses').then((res) => setExpenses(res.data));
  }, [user]);

  const deleteDraft = async (id) => {
    if (!window.confirm('Delete this draft?')) return;
    await api.delete(`/expenses/${id}`);
    setExpenses(expenses.filter((e) => e._id !== id));
  };

  const submitDraft = async (id) => {
    try {
      await api.post(`/expenses/${id}/submit`);
      const res = await api.get('/expenses');
      setExpenses(res.data);
    } catch (err) {
      alert(err.response?.data?.message || 'Submit failed');
    }
  };

  const drafts = expenses.filter((e) => e.status === 'Draft');
  const submitted = expenses.filter((e) => e.status !== 'Draft');

  return (
    <div style={styles.page}>
      {/* Header */}
      <div style={styles.header}>
        <div>
          <h2 style={{ margin: 0 }}>My Expenses</h2>
          <span style={styles.subtitle}>Welcome, {user?.name}</span>
        </div>
        <div style={{ display: 'flex', gap: '0.5rem' }}>
          <button style={styles.btnPrimary} onClick={() => navigate('/employee/submit')}>
            + New Expense
          </button>
          <button style={styles.btnLogout} onClick={logout}>Logout</button>
        </div>
      </div>

      {/* Expense Table */}
      <div style={styles.tableWrap}>
        <table style={styles.table}>
          <thead>
            <tr style={styles.thead}>
              <th style={styles.th}>Date</th>
              <th style={styles.th}>Expense Type</th>
              <th style={styles.th}>Vendor</th>
              <th style={styles.th}>Amount</th>
              <th style={styles.th}>Currency</th>
              <th style={styles.th}>Status</th>
              <th style={styles.th}>Action</th>
            </tr>
          </thead>
          <tbody>
            {expenses.length === 0 && (
              <tr>
                <td colSpan={7} style={{ textAlign: 'center', padding: '2rem', color: '#9ca3af' }}>
                  No expenses yet. Submit your first expense.
                </td>
              </tr>
            )}
            {expenses.map((e) => (
              <tr key={e._id} style={styles.tr}>
                <td style={styles.td}>{new Date(e.date).toLocaleDateString()}</td>
                <td style={styles.td}>{e.category}</td>
                <td style={styles.td}>{e.ocrData?.vendor || '—'}</td>
                <td style={styles.td}>{Number(e.amount).toFixed(2)}</td>
                <td style={styles.td}>{e.currency}</td>
                <td style={styles.td}>
                  <span style={{ ...styles.badge, ...STATUS_COLOR[e.status] }}>{e.status}</span>
                </td>
                <td style={styles.td}>
                  <button style={styles.btnView} onClick={() => navigate(`/expenses/${e._id}`)}>
                    View
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

const styles = {
  page: { maxWidth: '1000px', margin: '2rem auto', padding: '0 1.5rem', fontFamily: 'sans-serif' },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' },
  subtitle: { color: '#6b7280', fontSize: '0.9rem' },
  tableWrap: { background: '#fff', borderRadius: '8px', boxShadow: '0 1px 4px rgba(0,0,0,0.08)', overflow: 'hidden' },
  table: { width: '100%', borderCollapse: 'collapse' },
  thead: { background: '#f9fafb' },
  th: { padding: '0.75rem 1rem', textAlign: 'left', fontSize: '0.8rem', fontWeight: 700, color: '#374151', textTransform: 'uppercase', letterSpacing: '0.05em', borderBottom: '1px solid #e5e7eb' },
  tr: { borderBottom: '1px solid #f3f4f6' },
  td: { padding: '0.75rem 1rem', fontSize: '0.9rem', color: '#374151' },
  badge: { padding: '0.2rem 0.7rem', borderRadius: '999px', fontSize: '0.78rem', fontWeight: 600 },
  btnPrimary: { padding: '0.5rem 1.2rem', background: '#4f46e5', color: '#fff', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: 600 },
  btnLogout: { padding: '0.5rem 1rem', background: '#f3f4f6', color: '#374151', border: 'none', borderRadius: '6px', cursor: 'pointer' },
  btnView: { padding: '0.3rem 0.8rem', background: '#ede9fe', color: '#4f46e5', border: 'none', borderRadius: '4px', cursor: 'pointer', fontWeight: 600, fontSize: '0.82rem' },
};
